<script setup lang="ts">
import { CmsApiError, cmsApi } from '~/utils/cms-api'

type Page = 'members'|'orders'|'issues'
const props=defineProps<{page:Page}>()
const title={members:'會員管理',orders:'訂單管理',issues:'問題回報'} as const
const checking=ref(true),loggedIn=ref(false),loading=ref(false),adminEmail=ref(''),loginEmail=ref(''),loginPassword=ref(''),error=ref(''),notice=ref('')
const query=ref(''),filter=ref(''),filter2=ref(''),filter3=ref(''),cursor=ref(''),items=ref<any[]>([]),detail=ref<any>(null),detailOpen=ref(false)
const startDate=ref(''),endDate=ref('')
const confirmOpen=ref(false),confirmPassword=ref(''),reason=ref(''),suspendAction=ref(false),note=ref('')
const grantOpen=ref(false),grantKind=ref<'premium'|'points'>('premium'),grantPreset=ref('7'),grantAmount=ref(7),grantReason=ref(''),grantPassword=ref(''),grantOperationId=ref('')
const hint='fate-cms-session'
const format=(v?:string)=>v?new Intl.DateTimeFormat('zh-TW',{dateStyle:'medium',timeStyle:'short'}).format(new Date(v)):'—'
const money=(v=0)=>new Intl.NumberFormat('zh-TW',{style:'currency',currency:'TWD',maximumFractionDigits:0}).format(v)
const statusName:Record<string,string>={active:'正常',suspended:'已停權',pending:'待處理',in_progress:'處理中',resolved:'已解決',closed:'已關閉',paid:'已付款',failed:'失敗',cancelled:'已取消',refunded:'已退款',past_due:'扣款異常',expired:'已到期',processed:'已處理'}
const priorityName:Record<string,string>={low:'低',normal:'一般',high:'高',urgent:'緊急'}

function handle(e:unknown){if(e instanceof CmsApiError&&e.status===401){sessionStorage.removeItem(hint);loggedIn.value=false};error.value=e instanceof Error?e.message:'操作失敗'}
async function restore(){try{const s=await cmsApi<{email:string}>('/auth/session');adminEmail.value=s.email;loggedIn.value=true;await load()}catch{sessionStorage.removeItem(hint)}finally{checking.value=false}}
async function login(){loading.value=true;error.value='';try{const s=await cmsApi<{email:string}>('/auth/login',{method:'POST',body:JSON.stringify({email:loginEmail.value,password:loginPassword.value})});adminEmail.value=s.email;loggedIn.value=true;sessionStorage.setItem(hint,'1');await load()}catch(e){handle(e)}finally{loginPassword.value='';loading.value=false}}
async function logout(){try{await cmsApi('/auth/logout',{method:'POST'})}finally{sessionStorage.removeItem(hint);loggedIn.value=false}}
function endpoint(next=''){const params=new URLSearchParams({limit:'20'});if(query.value.trim())params.set('query',query.value.trim());if(next)params.set('cursor',next);if(props.page==='members'){if(filter.value)params.set('status',filter.value);if(filter2.value)params.set('premium',filter2.value)}else if(props.page==='orders'){if(filter.value)params.set('status',filter.value)}else{if(filter.value)params.set('status',filter.value);if(filter2.value)params.set('priority',filter2.value);if(filter3.value)params.set('type',filter3.value)}if(props.page!=='members'){if(startDate.value)params.set('start_date',startDate.value);if(endDate.value)params.set('end_date',endDate.value)}return `/${props.page==='members'?'users':props.page}?${params}`}
async function load(next=''){loading.value=true;error.value='';try{const r=await cmsApi<{items:any[];next_cursor:string}>(endpoint(next));items.value=next?[...items.value,...r.items]:r.items;cursor.value=r.next_cursor||''}catch(e){handle(e)}finally{loading.value=false}}
async function openDetail(item:any){loading.value=true;error.value='';try{detail.value=await cmsApi(`/${props.page==='members'?'users':props.page}/${item.uuid}`);detailOpen.value=true}catch(e){handle(e)}finally{loading.value=false}}
function requestStatus(suspended:boolean){suspendAction.value=suspended;confirmPassword.value='';reason.value='';confirmOpen.value=true}
async function saveMemberStatus(){loading.value=true;error.value='';try{const id=detail.value.uuid;const action=suspendAction.value?'suspend':'unsuspend';const r=await cmsApi<{message:string}>(`/users/${id}/${action}`,{method:'POST',body:JSON.stringify({password:confirmPassword.value,reason:reason.value})});notice.value=r.message;confirmOpen.value=false;detail.value=await cmsApi(`/users/${id}`);await load()}catch(e){handle(e)}finally{confirmPassword.value='';loading.value=false}}
function requestGrant(kind:'premium'|'points'){grantKind.value=kind;grantPreset.value=kind==='premium'?'7':'100';grantAmount.value=kind==='premium'?7:100;grantReason.value='';grantPassword.value='';grantOperationId.value=crypto.randomUUID();grantOpen.value=true}
function syncGrantPreset(){if(grantPreset.value!=='other')grantAmount.value=Number(grantPreset.value)}
async function saveGrant(){if(!detail.value)return;loading.value=true;error.value='';try{let result:{message:string};if(grantKind.value==='premium'){result=await cmsApi('/premium/grants',{method:'POST',body:JSON.stringify({user_id:detail.value.uuid,days:grantAmount.value,password:grantPassword.value,operation_id:grantOperationId.value})})}else{result=await cmsApi(`/users/${detail.value.uuid}/points/grants`,{method:'POST',body:JSON.stringify({points:grantAmount.value,reason:grantReason.value,password:grantPassword.value,operation_id:grantOperationId.value})})}notice.value=result.message;grantOpen.value=false;detail.value=await cmsApi(`/users/${detail.value.uuid}`);await load()}catch(e){handle(e)}finally{grantPassword.value='';loading.value=false}}
async function updateIssue(){loading.value=true;try{const id=detail.value.report.uuid;await cmsApi(`/issues/${id}`,{method:'PATCH',body:JSON.stringify({status:detail.value.report.status,priority:detail.value.report.priority})});notice.value='問題回報已更新';detail.value=await cmsApi(`/issues/${id}`);await load()}catch(e){handle(e)}finally{loading.value=false}}
async function addNote(){if(!note.value.trim())return;loading.value=true;try{const id=detail.value.report.uuid;await cmsApi(`/issues/${id}/notes`,{method:'POST',body:JSON.stringify({note:note.value})});note.value='';detail.value=await cmsApi(`/issues/${id}`);notice.value='處理紀錄已新增'}catch(e){handle(e)}finally{loading.value=false}}
onMounted(()=>sessionStorage.getItem(hint)==='1'?restore():(checking.value=false))
</script>

<template>
  <div v-if="checking" class="center"><span class="spinner"/></div>
  <div v-else-if="!loggedIn" class="login-shell"><form class="login-card" @submit.prevent="login"><b class="mark">映</b><small>FATEJYC ADMIN</small><h1>管理後台</h1><p>請使用管理員帳號登入，此頁不提供註冊。</p><label>管理員帳號<input v-model="loginEmail" type="email" required autocomplete="username"></label><label>密碼<input v-model="loginPassword" type="password" required autocomplete="current-password"></label><p v-if="error" class="alert error">{{ error }}</p><button class="primary full" :disabled="loading">{{ loading?'登入中…':'登入' }}</button></form></div>
  <div v-else class="shell">
    <aside><div><small>FATEJYC</small><h2>CMS</h2></div><nav><NuxtLink to="/cms/">數據總覽</NuxtLink><NuxtLink to="/cms/members/" :class="{active:page==='members'}">會員管理</NuxtLink><NuxtLink to="/cms/orders/" :class="{active:page==='orders'}">訂單管理</NuxtLink><NuxtLink to="/cms/issues/" :class="{active:page==='issues'}">問題回報</NuxtLink></nav><div class="admin"><small>目前登入</small><span>{{ adminEmail }}</span><button class="link" @click="logout">登出</button></div></aside>
    <main><header><div><small>管理中心</small><h1>{{ title[page] }}</h1></div><button class="secondary" :disabled="loading" @click="load()">重新整理</button></header><p v-if="error" class="alert error">{{ error }}</p><p v-if="notice" class="alert success">{{ notice }}</p>
      <section class="panel"><form class="filters" @submit.prevent="load()">
        <input v-model="query" :placeholder="page==='members'?'搜尋 Email、姓名或 UUID':page==='orders'?'搜尋 Email、訂單或交易編號':'搜尋 Email 或回報內容'">
        <select v-model="filter"><option value="">全部狀態</option><template v-if="page==='members'"><option value="active">正常</option><option value="suspended">已停權</option></template><template v-else-if="page==='orders'"><option v-for="s in ['pending','paid','failed','cancelled','refunded']" :key="s" :value="s">{{ statusName[s] }}</option></template><template v-else><option v-for="s in ['pending','in_progress','resolved','closed']" :key="s" :value="s">{{ statusName[s] }}</option></template></select>
        <select v-if="page!=='orders'" v-model="filter2"><option value="">{{ page==='members'?'全部會員':'全部優先級' }}</option><template v-if="page==='members'"><option value="premium">Premium</option><option value="standard">一般會員</option></template><template v-else><option v-for="p in ['low','normal','high','urgent']" :key="p" :value="p">{{ priorityName[p] }}</option></template></select>
        <select v-if="page==='issues'" v-model="filter3"><option value="">全部類型</option><option value="系統建議">系統建議</option><option value="BUG">BUG</option><option value="會員權益">會員權益</option></select>
        <label v-if="page!=='members'" class="date-filter">起日<input v-model="startDate" type="date" :max="endDate||undefined"></label><label v-if="page!=='members'" class="date-filter">迄日<input v-model="endDate" type="date" :min="startDate||undefined"></label>
        <button class="primary">查詢</button><button v-if="page!=='members'&&(startDate||endDate)" type="button" class="secondary" @click="startDate='';endDate='';load()">清除日期</button>
      </form>
        <div class="table-wrap"><table><thead><tr v-if="page==='members'"><th>會員</th><th>狀態</th><th>Premium</th><th>點數</th><th>Web 消費</th><th>註冊時間</th></tr><tr v-else-if="page==='orders'"><th>訂單編號</th><th>會員</th><th>商品</th><th>狀態</th><th>金額</th><th>建立時間</th></tr><tr v-else><th>會員</th><th>類型</th><th>內容</th><th>狀態</th><th>優先級</th><th>回報時間</th></tr></thead><tbody><tr v-for="item in items" :key="item.uuid" @click="openDetail(item)"><template v-if="page==='members'"><td><b>{{ item.name||'未設定姓名' }}</b><small>{{ item.email }}</small></td><td><span :class="['badge',item.account_status]">{{ statusName[item.account_status] }}</span></td><td>{{ item.is_premium?'Premium':'一般' }}</td><td>{{ item.points }}</td><td>{{ money(item.web_spend) }}</td><td>{{ format(item.created_at) }}</td></template><template v-else-if="page==='orders'"><td>{{ item.merchant_order_no }}</td><td>{{ item.email }}</td><td>{{ item.product_id }}</td><td><span :class="['badge',item.status]">{{ statusName[item.status]||item.status }}</span></td><td>{{ money(item.amount) }}</td><td>{{ format(item.created_at) }}</td></template><template v-else><td>{{ item.email }}</td><td>{{ item.issue_type }}</td><td class="description">{{ item.description }}</td><td><span :class="['badge',item.status]">{{ statusName[item.status] }}</span></td><td>{{ priorityName[item.priority] }}</td><td>{{ format(item.created_at) }}</td></template></tr></tbody></table><p v-if="!items.length&&!loading" class="empty">目前沒有資料</p></div><button v-if="cursor" class="secondary more" :disabled="loading" @click="load(cursor)">載入更多</button>
      </section>
    </main>
    <div v-if="detailOpen" class="backdrop" @click.self="detailOpen=false"><section class="drawer"><button class="close" aria-label="關閉" @click="detailOpen=false">×</button>
      <template v-if="page==='members'&&detail"><small>MEMBER DETAIL</small><h2>{{ detail.name||'未設定姓名' }}</h2><p>{{ detail.email }}</p><div class="facts"><p><span>帳號狀態</span><b>{{ statusName[detail.account_status] }}</b></p><p><span>Premium</span><b>{{ detail.premium?.is_premium?'有效至 '+format(detail.premium?.effective_expires_at):'一般會員' }}</b></p><p><span>點數</span><b>{{ detail.points }}</b></p><p><span>Web 消費</span><b>{{ money(detail.web_spend) }}</b></p><p><span>Web 訂單</span><b>{{ detail.web_orders }} 筆</b></p><p><span>註冊時間</span><b>{{ format(detail.created_at) }}</b></p></div>
        <section class="rights"><div><h3>會員權益</h3><p class="muted">Premium 與點數發放皆會留下完整稽核紀錄。</p></div><div class="rights-actions"><button class="primary" @click="requestGrant('premium')">增加 Premium 天數</button><button class="secondary" @click="requestGrant('points')">發放點數</button></div></section>
        <h3 v-if="detail.premium_grants?.length||detail.point_grants?.length">近期後台權益異動</h3><div class="notes"><p v-for="g in detail.premium_grants" :key="g.operation_id"><b>Premium +{{ g.days }} 天</b><span>到期 {{ format(g.expires_at) }}</span><small>{{ g.admin_email }}・{{ format(g.created_at) }}</small></p><p v-for="g in detail.point_grants" :key="g.operation_id"><b>點數 +{{ g.points }}</b><span>{{ g.reason }}・餘額 {{ g.balance_after }}</span><small>{{ g.admin_email }}・{{ format(g.created_at) }}</small></p></div>
        <div v-if="detail.account_status==='suspended'" class="suspend-info"><b>停權原因</b><p>{{ detail.suspended_reason }}</p><small>{{ format(detail.suspended_at) }}・{{ detail.suspended_by }}</small></div><button v-if="detail.account_status==='active'" class="danger" @click="requestStatus(true)">停權會員</button><button v-else class="primary" @click="requestStatus(false)">解除停權</button></template>
      <template v-else-if="page==='orders'&&detail"><small>ORDER DETAIL</small><h2>{{ detail.order.merchant_order_no }}</h2><p>{{ detail.order.email }}</p><div class="facts"><p><span>付款狀態</span><b>{{ statusName[detail.order.status]||detail.order.status }}</b></p><p><span>金額</span><b>{{ money(detail.order.amount) }}</b></p><p><span>藍新交易編號</span><b>{{ detail.order.provider_trade_no||'—' }}</b></p><p><span>付款時間</span><b>{{ format(detail.order.paid_at) }}</b></p></div><h3>訂閱狀態</h3><p v-if="detail.subscription">{{ statusName[detail.subscription.status]||detail.subscription.status }}・下次扣款 {{ format(detail.subscription.next_charge_at) }}・{{ detail.subscription.will_renew?'會自動續訂':'不再續訂' }}</p><p v-else class="muted">此訂單不是訂閱商品</p><h3>處理時間軸</h3><div class="timeline"><p v-for="e in detail.webhook_events" :key="e.uuid"><b>Webhook · {{ statusName[e.status]||e.status }}</b><span>{{ e.event_type }}　{{ format(e.received_at) }}</span><em v-if="e.error_message">{{ e.error_message }}</em></p><p v-for="c in detail.charges" :key="c.uuid"><b>定期扣款 · {{ statusName[c.status]||c.status }}</b><span>{{ money(c.amount) }}　{{ format(c.created_at) }}</span></p><p v-for="f in detail.fulfillments" :key="f.uuid"><b>權益已發放 · {{ f.grant_type }}</b><span>數量 {{ f.grant_amount }}　{{ format(f.created_at) }}</span></p><p v-if="!detail.webhook_events.length&&!detail.charges.length&&!detail.fulfillments.length" class="muted">目前沒有後續處理紀錄</p></div></template>
      <template v-else-if="page==='issues'&&detail"><small>ISSUE DETAIL</small><h2>{{ detail.report.issue_type }}</h2><p>{{ detail.report.email }}・{{ format(detail.report.created_at) }}</p><blockquote>{{ detail.report.description }}</blockquote><div class="issue-controls"><label>處理狀態<select v-model="detail.report.status"><option v-for="s in ['pending','in_progress','resolved','closed']" :key="s" :value="s">{{ statusName[s] }}</option></select></label><label>優先級<select v-model="detail.report.priority"><option v-for="p in ['low','normal','high','urgent']" :key="p" :value="p">{{ priorityName[p] }}</option></select></label><button class="primary" @click="updateIssue">儲存狀態</button></div><h3>內部處理紀錄</h3><div class="notes"><p v-for="n in detail.notes" :key="n.uuid"><b>{{ n.admin_email }}</b><span>{{ n.note }}</span><small>{{ format(n.created_at) }}</small></p><p v-if="!detail.notes.length" class="muted">尚無處理紀錄</p></div><form @submit.prevent="addNote"><label>新增內部紀錄<textarea v-model="note" maxlength="2000" rows="4" required></textarea></label><button class="primary">新增紀錄</button></form></template>
    </section></div>
    <div v-if="confirmOpen" class="backdrop"><form class="modal" @submit.prevent="saveMemberStatus"><h2>{{ suspendAction?'確認停權會員':'確認解除停權' }}</h2><label>操作原因<textarea v-model="reason" maxlength="500" required rows="3"/></label><label>管理員密碼<input v-model="confirmPassword" type="password" required autocomplete="current-password"></label><div class="actions"><button type="button" class="secondary" @click="confirmOpen=false">取消</button><button :class="suspendAction?'danger':'primary'" :disabled="loading">確認操作</button></div></form></div>
    <div v-if="grantOpen" class="backdrop"><form class="modal" @submit.prevent="saveGrant"><small>再次驗證</small><h2>{{ grantKind==='premium'?'增加 Premium 天數':'發放點數' }}</h2><p>對象：{{ detail?.email }}</p>
      <label>{{ grantKind==='premium'?'期間':'點數' }}<select v-model="grantPreset" @change="syncGrantPreset"><template v-if="grantKind==='premium'"><option value="1">一天</option><option value="3">三天</option><option value="7">一週</option><option value="30">一個月</option><option value="90">三個月</option><option value="180">半年</option><option value="365">一年</option></template><template v-else><option value="50">50 點</option><option value="100">100 點</option><option value="300">300 點</option><option value="500">500 點</option><option value="1000">1000 點</option></template><option value="other">其他</option></select></label>
      <label v-if="grantPreset==='other'">自訂{{ grantKind==='premium'?'天數':'點數' }}<input v-model.number="grantAmount" type="number" min="1" :max="grantKind==='premium'?1000:1000" required></label>
      <label v-if="grantKind==='points'">發放原因<textarea v-model="grantReason" maxlength="500" rows="3" required></textarea></label>
      <label>管理員密碼<input v-model="grantPassword" type="password" required autocomplete="current-password"></label><div class="actions"><button type="button" class="secondary" @click="grantOpen=false">取消</button><button class="primary" :disabled="loading">{{ loading?'處理中…':'確認操作' }}</button></div></form></div>
  </div>
</template>

<style scoped>
*{box-sizing:border-box}.center,.login-shell{min-height:100dvh;display:grid;place-items:center;padding:24px}.login-shell{background:#eef3f1}.login-card,.panel,.drawer,.modal{background:#fff;border:1px solid #d8e3df;border-radius:18px}.login-card{width:min(430px,100%);padding:38px;display:grid;gap:14px}.mark{width:48px;height:48px;display:grid;place-items:center;border-radius:14px;background:#176b5b;color:#fff;font-size:22px}.shell{min-height:100dvh;display:grid;grid-template-columns:240px 1fr;background:#f5f7f6;color:#183532}aside{position:sticky;top:0;height:100dvh;padding:30px 24px;background:#123e37;color:#fff;display:flex;flex-direction:column}aside h2{margin:4px 0;font-size:28px}nav{display:grid;gap:8px;margin-top:48px}nav a{padding:11px 12px;color:#d8ebe6;text-decoration:none;border-radius:9px}nav a:hover,nav a.active{background:#ffffff18;color:#fff}.admin{margin-top:auto;display:grid;gap:6px;overflow-wrap:anywhere}.link{background:none;color:#9cd3c7;text-align:left;padding:8px 0}main{padding:42px clamp(24px,4vw,64px);min-width:0}main>header{display:flex;justify-content:space-between;align-items:center;margin-bottom:26px}h1,h2,h3{margin:4px 0 12px}button{border:0;border-radius:10px;padding:11px 16px;font:inherit;font-weight:750;cursor:pointer}.primary{background:#176b5b;color:#fff}.secondary{background:#fff;border:1px solid #cbd9d5;color:#28544c}.danger{background:#a13e3e;color:#fff}.full{width:100%}.panel{padding:22px}.filters{display:grid;grid-template-columns:minmax(260px,1fr) 180px 180px auto;gap:10px}input,select,textarea{width:100%;border:1px solid #cbd9d5;border-radius:10px;padding:11px 13px;background:#fff;font:inherit;color:inherit}label{display:grid;gap:7px;font-size:13px;font-weight:700}.table-wrap{overflow:auto}table{width:100%;border-collapse:collapse;margin-top:18px;text-align:left}th,td{padding:13px;border-bottom:1px solid #e1e9e6;white-space:nowrap;font-size:13px}tbody tr{cursor:pointer}tbody tr:hover{background:#f2f7f5}td small,td b{display:block}.description{max-width:340px;overflow:hidden;text-overflow:ellipsis}.badge{display:inline-block;padding:5px 9px;border-radius:99px;background:#edf1ef}.badge.paid,.badge.active,.badge.resolved{background:#dff3e9;color:#176044}.badge.failed,.badge.suspended,.badge.urgent{background:#f7e3e3;color:#943838}.more{margin-top:16px}.empty{text-align:center;color:#71827f;padding:28px}.alert{padding:12px 14px;border-radius:10px}.error{color:#9d3131;background:#fbe9e9}.success{color:#176044;background:#def4e9}.backdrop{position:fixed;inset:0;background:#102c2770;z-index:30;display:flex;justify-content:flex-end}.drawer{height:100%;width:min(620px,100%);border-radius:0;padding:36px;overflow:auto;position:relative}.close{position:absolute;right:20px;top:16px;background:none;font-size:28px}.facts{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:22px 0}.facts p{display:grid;gap:5px;background:#f3f7f5;padding:13px;border-radius:10px;margin:0}.facts span,.muted{color:#71827f;font-size:12px}.suspend-info,blockquote{padding:15px;background:#fff3e5;border-radius:10px;margin:18px 0}.timeline,.notes{display:grid;gap:10px;margin:14px 0 22px}.timeline p,.notes p{display:grid;gap:5px;padding:13px;border-left:3px solid #2b927b;background:#f4f8f6;margin:0}.timeline span,.notes span,.notes small{font-size:13px}.timeline em{color:#9d3131}.issue-controls{display:grid;grid-template-columns:1fr 1fr auto;gap:10px;align-items:end;margin:20px 0}.modal{width:min(480px,calc(100% - 32px));padding:28px;margin:auto;display:grid;gap:16px}.actions{display:flex;justify-content:flex-end;gap:10px}.spinner{width:34px;height:34px;border:3px solid #c9ddd7;border-top-color:#176b5b;border-radius:50%;animation:spin .8s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}button:disabled{opacity:.55}
.filters{display:flex;flex-wrap:wrap;align-items:end}.filters>input{flex:1 1 280px}.filters>select{flex:0 1 170px}.filters>.date-filter{flex:0 1 155px}.date-filter{gap:4px;color:#61736f}.rights{display:flex;align-items:center;justify-content:space-between;gap:16px;padding:18px;margin:20px 0;background:#edf6f2;border-radius:12px}.rights-actions{display:flex;gap:8px;flex-wrap:wrap}
